cURLPythonJavaScript <pre><code># Export with intervention defaults
curl -X POST https://iwmi-leaf.onrender.com/api/export/csv \
  -H "Content-Type: application/json" \
  -d '{"intervention": "Organic Farming"}' \
  -o leaf_data.csv

# Export raw data (no scores)
curl -X POST https://iwmi-leaf.onrender.com/api/export/csv \
  -H "Content-Type: application/json" \
  -d '{}' \
  -o leaf_raw.csv

# Export with custom filters
curl -X POST https://iwmi-leaf.onrender.com/api/export/csv \
  -H "Content-Type: application/json" \
  -d '{
    "filters": [
      {"column": "AD", "min_val": 20, "max_val": 60, "weight": 1.0},
      {"column": "WA", "min_val": 30, "max_val": 70, "weight": 0.8}
    ],
    "logic": "OR"
  }' \
  -o leaf_filtered.csv
</code></pre> <pre><code>import requests
import pandas as pd
from io import StringIO

# Download CSV with feasibility scores
response = requests.post(
    "https://iwmi-leaf.onrender.com/api/export/csv",
    json={"intervention": "Organic Farming"}
)

# Save to file
with open("leaf_data.csv", "wb") as f:
    f.write(response.content)

# Or load directly into pandas
df = pd.read_csv(StringIO(response.text))
print(f"Rows: {len(df)}, Columns: {len(df.columns)}")
print(df[['Block_name', 'Dist_Name', 'feasibility_score']].head())

# Top 10 blocks by feasibility
top = df.nlargest(10, 'feasibility_score')
print("\nTop 10 blocks:")
print(top[['Block_name', 'Dist_Name', 'feasibility_score', 'feasibility_class']])
</code></pre> <pre><code>const response = await fetch('/api/export/csv', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ intervention: 'Organic Farming' })
});

// Trigger browser download
const blob = await response.blob();
const url = URL.createObjectURL(blob);
const a = document.createElement('a');
a.href = url;
a.download = 'leaf_data.csv';
document.body.appendChild(a);
a.click();
document.body.removeChild(a);
URL.revokeObjectURL(url);
</code></pre> <p>Opening in Excel</p> <p>The downloaded CSV can be opened directly in Excel, Google Sheets, or LibreOffice Calc. All numeric values are formatted for spreadsheet compatibility.</p>

cURLPythonJavaScript <pre><code># Using intervention defaults
curl -X POST https://iwmi-leaf.onrender.com/api/calculate-feasibility \
  -H "Content-Type: application/json" \
  -d '{"intervention": "Organic Farming", "logic": "AND"}'

# Using custom filters
curl -X POST https://iwmi-leaf.onrender.com/api/calculate-feasibility \
  -H "Content-Type: application/json" \
  -d '{
    "filters": [
      {"column": "AD", "min_val": 20, "max_val": 60, "weight": 1.0},
      {"column": "WA", "min_val": 30, "max_val": 70, "weight": 0.8}
    ],
    "logic": "AND"
  }'
</code></pre> <pre><code>import requests

# Calculate feasibility with custom filters
response = requests.post(
    "https://iwmi-leaf.onrender.com/api/calculate-feasibility",
    json={
        "filters": [
            {"column": "AD", "min_val": 20, "max_val": 60, "weight": 1.0},
            {"column": "WA", "min_val": 30, "max_val": 70, "weight": 0.8}
        ],
        "logic": "AND"
    }
)
result = response.json()

print(f"Mean feasibility: {result['statistics']['mean_score']:.1f}")
print(f"High feasibility blocks: {result['statistics'].get('high_count', 0)}")

# Find top-scoring blocks
features = result['geojson']['features']
top = sorted(features, key=lambda f: f['properties'].get('feasibility_score', 0), reverse=True)
for f in top[:5]:
    p = f['properties']
    print(f"  {p['Block_name']}: {p['feasibility_score']:.1f} ({p['feasibility_class']})")
</code></pre> <pre><code>const response = await fetch('/api/calculate-feasibility', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    intervention: 'Organic Farming',
    logic: 'AND'
  })
});
const result = await response.json();

console.log(`Mean score: ${result.statistics.mean_score}`);
// Add scored GeoJSON to map
L.geoJSON(result.geojson, {
  style: feature =&gt; ({
    fillColor: feature.properties.feasibility_color,
    fillOpacity: 0.7
  })
}).addTo(map);
</code></pre>

