cURLPythonJavaScript <pre><code>curl "https://iwmi-leaf.onrender.com/api/intervention/Organic%20Farming/config"
</code></pre> <pre><code>import requests

name = "Organic Farming"
r = requests.get(f"https://iwmi-leaf.onrender.com/api/intervention/{name}/config")
config = r.json()

print(f"Intervention: {config['name']}")
print(f"Variables: {len(config['variables'])}")
for v in config['variables']:
    print(f"  {v['label']} ({v['field']}): {v['range_min']}–{v['range_max']} "
          f"(weight {v['weight']}, prefer {v['preference']})")
</code></pre> <pre><code>const name = encodeURIComponent('Organic Farming');
const r = await fetch(`/api/intervention/${name}/config`);
